proof_block:
reveal(StrictlyOrderedVec::valid);
K::cmp_properties();

let pre = pre_self_@;
let post1 = post1_self_@;
let post2 = post2_self_@;

assert(post1 == pre.insert(r1 as int, k));
assert(post2 == pre.insert(r2 as int, k));
assert(post1.len() == pre.len() + 1);
assert(post2.len() == pre.len() + 1);
assert(sorted(pre));
assert(sorted(post1));
assert(sorted(post2));
assert(0 <= r1);
assert(0 <= r2);
assert((r1 as int) < post1.len());
assert((r2 as int) < post2.len());

if r1 < r2 {
    let i1: int = r1 as int;
    let j2: int = r2 as int;
    assert(0 <= i1);
    assert(i1 < j2);
    assert(j2 <= pre.len());
    assert(i1 < pre.len());
    assert(j2 - 1 >= 0);
    assert(j2 - 1 < pre.len());
    assert(i1 + 1 <= pre.len());

    // post1 = pre.insert(i1, k): so post1[i1] = k and post1[i1+1] = pre[i1].
    assert(post1[i1] == k);
    assert(i1 + 1 < post1.len());
    assert(post1[i1 + 1] == pre[i1]);
    // sorted(post1) -> post1[i1].cmp_spec(post1[i1+1]).lt(), i.e. k < pre[i1].
    assert(post1[i1].cmp_spec(post1[i1 + 1]).lt());
    assert(k.cmp_spec(pre[i1]).lt());

    // post2 = pre.insert(j2, k): so post2[j2-1] = pre[j2-1] and post2[j2] = k.
    assert(post2[j2 - 1] == pre[j2 - 1]);
    assert(j2 < post2.len());
    assert(post2[j2] == k);
    // sorted(post2) -> pre[j2-1] < k.
    assert(post2[j2 - 1].cmp_spec(post2[j2]).lt());
    assert(pre[j2 - 1].cmp_spec(k).lt());

    if i1 + 1 < j2 {
        assert(i1 < j2 - 1);
        // sorted(pre) -> pre[i1] < pre[j2-1].
        assert(pre[i1].cmp_spec(pre[j2 - 1]).lt());
        // Transitivity: k < pre[i1] < pre[j2-1] < k.
        assert(k.cmp_spec(pre[j2 - 1]).lt());
        assert(k.cmp_spec(k).lt());
    } else {
        assert(i1 + 1 == j2);
        assert(i1 == j2 - 1);
        assert(pre[i1] == pre[j2 - 1]);
        // k < pre[i1] = pre[j2-1] < k.
        assert(k.cmp_spec(pre[j2 - 1]).lt());
        assert(k.cmp_spec(k).lt());
    }
    // Reflexivity from cmp_properties: k.cmp_spec(k).eq().
    assert(k.cmp_spec(k).eq());
    assert(false);
}

if r2 < r1 {
    let i2: int = r2 as int;
    let j1: int = r1 as int;
    assert(0 <= i2);
    assert(i2 < j1);
    assert(j1 <= pre.len());
    assert(i2 < pre.len());
    assert(j1 - 1 >= 0);
    assert(j1 - 1 < pre.len());
    assert(i2 + 1 <= pre.len());

    assert(post2[i2] == k);
    assert(i2 + 1 < post2.len());
    assert(post2[i2 + 1] == pre[i2]);
    assert(post2[i2].cmp_spec(post2[i2 + 1]).lt());
    assert(k.cmp_spec(pre[i2]).lt());

    assert(post1[j1 - 1] == pre[j1 - 1]);
    assert(j1 < post1.len());
    assert(post1[j1] == k);
    assert(post1[j1 - 1].cmp_spec(post1[j1]).lt());
    assert(pre[j1 - 1].cmp_spec(k).lt());

    if i2 + 1 < j1 {
        assert(i2 < j1 - 1);
        assert(pre[i2].cmp_spec(pre[j1 - 1]).lt());
        assert(k.cmp_spec(pre[j1 - 1]).lt());
        assert(k.cmp_spec(k).lt());
    } else {
        assert(i2 + 1 == j1);
        assert(i2 == j1 - 1);
        assert(pre[i2] == pre[j1 - 1]);
        assert(k.cmp_spec(pre[j1 - 1]).lt());
        assert(k.cmp_spec(k).lt());
    }
    assert(k.cmp_spec(k).eq());
    assert(false);
}

// Both branches above are impossible, so r1 == r2.
assert(!(r1 < r2));
assert(!(r2 < r1));
assert(r1 == r2);
assert((r1 as int) == (r2 as int));
assert(pre.insert(r1 as int, k) == pre.insert(r2 as int, k));
assert(post1 == pre.insert(r1 as int, k));
assert(post2 == pre.insert(r2 as int, k));
assert(post1 =~= post2);
assert(post1 == post2);
assert(post1_self_@ == post2_self_@);
